import React from 'react';
import "../styles/help.css";
const Help = () => {
  return (
    <div className='help'>
      <h1>Help Center</h1>
      <p>
        If you need assistance, please refer to the following resources:
      </p>
      <ul>
        <li>
          <strong>Frequently Asked Questions (FAQ):</strong> Find answers to common questions about our services.
        </li>
        <li>
          <strong>Contact Support:</strong> Get in touch with our support team for personalized assistance.
        </li>
        <li>
          <strong>Live Chat:</strong> Use our live chat feature for real-time support during working hours.
        </li>
      </ul>
      <p>
        Our team is here to help you with any queries or issues you may encounter. Feel free to reach out!
      </p>
    </div>
  );
};

export default Help;
